def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 辅助函数：计算点集的超体积
    def compute_hypervolume(point_set: List[np.ndarray]) -> float:
        if not point_set:
            return 0.0
        hv = pg.hypervolume(np.array(point_set))
        return hv.compute(reference_point)

    # 阶段1: 贪心选择（带贡献缓存）
    selected_indices = []
    selected_points = []
    contribution_cache = {}

    # 预计算所有点的独立超体积
    independent_hv = {}
    for i in range(n):
        independent_hv[i] = compute_hypervolume([points[i]])

    while len(selected_indices) < k:
        best_idx = -1
        best_contrib = -np.inf

        # 遍历所有未选中的点
        for idx in range(n):
            if idx in selected_indices:
                continue

            # 计算贡献（带缓存）
            cache_key = (idx, tuple(sorted(selected_indices)))
            if cache_key in contribution_cache:
                contrib = contribution_cache[cache_key]
            else:
                if not selected_indices:
                    contrib = independent_hv[idx]
                else:
                    current_points = [points[i] for i in selected_indices]
                    hv_before = compute_hypervolume(current_points)
                    hv_after = compute_hypervolume(current_points + [points[idx]])
                    contrib = hv_after - hv_before
                contribution_cache[cache_key] = contrib

            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        # 添加选中的点
        selected_indices.append(best_idx)
        selected_points.append(points[best_idx])

    # 阶段2: 局部搜索优化（交换操作）
    improved = True
    max_iterations = 100

    for _ in range(max_iterations):
        if not improved:
            break

        improved = False

        # 尝试交换操作：用未选中的点替换选中的点
        for i in range(k):
            sel_idx = selected_indices[i]
            current_hv = compute_hypervolume(selected_points)

            # 找到最佳替换
            best_swap_idx = -1
            best_swap_improvement = 0

            for cand_idx in range(n):
                if cand_idx in selected_indices:
                    continue

                # 临时创建新集合
                temp_points = selected_points.copy()
                temp_points[i] = points[cand_idx]
                new_hv = compute_hypervolume(temp_points)

                improvement = new_hv - current_hv
                if improvement > best_swap_improvement:
                    best_swap_improvement = improvement
                    best_swap_idx = cand_idx

            # 执行交换
            if best_swap_idx != -1 and best_swap_improvement > 1e-10:
                selected_indices[i] = best_swap_idx
                selected_points[i] = points[best_swap_idx]
                improved = True
                break  # 一次只进行一次交换，然后重新评估

    return np.array(selected_points)

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume computation with caching
    hv_cache = {}
    def compute_hv(indices):
        key = tuple(sorted(indices))
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv = 0.0
        else:
            hv = pg.hypervolume(points[list(indices)]).compute(reference_point)
        if len(hv_cache) < 10000:
            hv_cache[key] = hv
        return hv

    # Greedy initialization with bounded tournament
    selected = set()
    for _ in range(k):
        best_idx = -1
        best_contrib = -np.inf
        candidates = random.sample([i for i in range(n) if i not in selected], 
                                   min(30, n - len(selected)))
        for idx in candidates:
            if not selected:
                contrib = compute_hv([idx])
            else:
                contrib = compute_hv(selected | {idx}) - compute_hv(selected)
            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx
        selected.add(best_idx)

    # TPOSS-like targeted mutation
    def mutate_mask(mask, k_val):
        b = np.sum(mask)
        a = n - b
        p0 = (abs(k_val - b) + k_val - b + 1) / (2 * a) if a > 0 else 0.0
        p1 = (abs(k_val - b) - k_val + b + 1) / (2 * b) if b > 0 else 0.0
        flip = np.random.rand(n) < np.where(mask, p1, p0)
        new_mask = mask ^ flip
        if np.sum(new_mask) == k_val:
            return new_mask
        return mask

    # ε-bounded hill-climbing swaps
    epsilon = 1e-10
    current_hv = compute_hv(selected)
    unselected = set(range(n)) - selected
    improved = True
    max_iter = 20

    for _ in range(max_iter):
        if not improved:
            break
        improved = False

        # Targeted mutation every 3 iterations
        if _ % 3 == 0:
            mask = np.zeros(n, dtype=bool)
            mask[list(selected)] = True
            new_mask = mutate_mask(mask, k)
            new_selected = set(np.where(new_mask)[0])
            if new_selected != selected:
                new_hv = compute_hv(new_selected)
                if new_hv > current_hv + epsilon:
                    selected = new_selected
                    unselected = set(range(n)) - selected
                    current_hv = new_hv
                    improved = True
                    continue

        # Focus swaps on low contributors
        contribs = {}
        for s in selected:
            contribs[s] = current_hv - compute_hv(selected - {s})
        low_contrib = sorted(contribs.keys(), key=lambda x: contribs[x])[:min(3, k)]

        for s in low_contrib:
            if improved:
                break
            candidates = random.sample(list(unselected), min(15, len(unselected)))
            for u in candidates:
                temp_set = (selected - {s}) | {u}
                hv_temp = compute_hv(temp_set)
                if hv_temp > current_hv + epsilon:
                    selected = temp_set
                    unselected = (unselected - {u}) | {s}
                    current_hv = hv_temp
                    improved = True
                    break

    return points[list(selected)]
